import type { Persona, ConditionEntry } from "../db/repositories/personasRepo";
import { updatePersona, updatePersonaXpLevel, updatePersonaConditions } from "../db/repositories/personasRepo";
import { parseGameTags, parseDuration } from "./inventoryTags";

/** Parses game tags (inventory + skill + level + conditions) from the AI
 *  response, updates the persona in DB, and returns the cleaned text. */
export async function processGameResponse(
  persona: Persona | null,
  text: string,
): Promise<string> {
  if (!persona) return text;
  const { cleanText, mutations, skillChanges, levelChanges, conditionChanges } = parseGameTags(text);
  if (mutations.length === 0 && skillChanges.length === 0 && levelChanges.length === 0 && conditionChanges.length === 0) return text;

  // Apply inventory mutations
  const inv = persona.inventory ? [...persona.inventory.map((i) => ({ ...i }))] : [];
  for (const m of mutations) {
    const existing = inv.find((i) => i.item.toLowerCase() === m.item.toLowerCase());
    if (m.op === "add") {
      if (existing) {
        existing.qty += m.qty;
      } else {
        inv.push({ item: m.item, qty: m.qty });
      }
    } else {
      if (existing) {
        existing.qty -= m.qty;
        if (existing.qty <= 0) inv.splice(inv.indexOf(existing), 1);
      }
    }
  }

  // Apply skill mutations
  const skills = persona.skills ? [...persona.skills.map((s) => ({ ...s }))] : [];
  for (const s of skillChanges) {
    const existing = skills.find((sk) => sk.name.toLowerCase() === s.name.toLowerCase());
    if (s.absolute !== null) {
      // Absolute set: [SKILL:+name:3]
      if (existing) {
        existing.level = s.absolute;
      } else {
        skills.push({ name: s.name, level: s.absolute });
      }
    } else if (s.delta > 0) {
      // Relative increase: [SKILL:name+2] or [SKILL:+name]
      if (existing) {
        existing.level += s.delta;
      } else {
        skills.push({ name: s.name, level: s.delta });
      }
    } else {
      // Decrease: [SKILL:name-1] — remove if <= 0
      if (existing) {
        existing.level = Math.max(0, existing.level + s.delta);
        if (existing.level <= 0) skills.splice(skills.indexOf(existing), 1);
      }
    }
  }

  // Apply level mutations
  let xp = persona.xp ?? 0;
  let level = persona.level ?? 1;
  let hasLevelChanges = false;
  for (const lc of levelChanges) {
    if (lc.xpDelta > 0) { xp += lc.xpDelta; hasLevelChanges = true; }
    if (lc.levelDelta > 0) { level += lc.levelDelta; hasLevelChanges = true; }
  }

  // Apply condition mutations
  const conditions: ConditionEntry[] = persona.conditions
    ? [...persona.conditions.map((c) => ({ ...c, modifiers: c.modifiers ? [...c.modifiers] : undefined }))]
    : [];
  let hasConditionChanges = false;

  for (const c of conditionChanges) {
    if (c.op === "remove") {
      const idx = conditions.findIndex((cond) => cond.name.toLowerCase() === c.name.toLowerCase());
      if (idx !== -1) {
        conditions.splice(idx, 1);
        hasConditionChanges = true;
      }
    } else {
      // Add or update condition
      const existing = conditions.find((cond) => cond.name.toLowerCase() === c.name.toLowerCase());
      const expiresAt = c.duration
        ? new Date(Date.now() + (parseDuration(c.duration) ?? 0)).toISOString()
        : null;
      if (existing) {
        existing.description = c.description || existing.description;
        existing.expiresAt = expiresAt;
        hasConditionChanges = true;
      } else {
        conditions.push({
          name: c.name,
          description: c.description || "",
          expiresAt,
        });
        hasConditionChanges = true;
      }
    }
  }

  try {
    await updatePersona(persona.id, {
      name: persona.name,
      gender: persona.gender,
      age: persona.age,
      race: persona.race,
      appearance: persona.appearance,
      progression: persona.progression,
      skills,
      inventory: inv,
      conditions,
    });
    if (hasLevelChanges) {
      await updatePersonaXpLevel(persona.id, xp, level);
    }
  } catch {
    // Non-critical
  }

  return cleanText;
}

