/**
 * Parses game tags from AI responses — inventory mutations, skill changes,
 * level progression, and faction reputation tags.
 * 
 * Inventory tags:
 *   [INV:+item_name]              — add item (qty 1)
 *   [INV:-item_name]              — remove item
 *   [INV:+n:item_name]            — add n items
 *   [INV:-n:item_name]            — remove n items
 * 
 * Skill tags:
 *   [SKILL:+name]                 — learn new skill (level 1)
 *   [SKILL:+name:level]           — learn skill at given level
 *   [SKILL:name+n]                — increase skill by n levels
 *   [SKILL:name-n]                — decrease skill by n levels
 * 
 * Level tags:
 *   [LEVEL:+xp]                   — add XP (e.g. [LEVEL:+50])
 *   [LEVEL:+level]                — increase level by 1 (e.g. [LEVEL:+1])
 * 
 * Faction tags:
 *   [FACTION:+name:delta]         — adjust reputation by delta (or create at delta)
 *   [FACTION:name]                — show current reputation (no-op in parsing)
 * 
 * Returns the cleaned text (all tags removed) and parsed mutations.
 */
export interface InvMutation {
  op: "add" | "remove";
  item: string;
  qty: number;
}

export interface SkillMutation {
  name: string;
  /** Positive = increase, negative = decrease, 0 = set absolute */
  delta: number;
  absolute: number | null; // used for [SKILL:+name:level]
}

export interface LevelMutation {
  xpDelta: number;
  levelDelta: number;
}

export interface ConditionMutation { op: "add" | "remove"; name: string; description?: string; duration?: string; }

export interface ConditionMutation { op: "add" | "remove"; name: string; description?: string; duration?: string; }

export interface FactionMutation {
  /** Faction name (lowercased for matching). */
  name: string;
  /** Reputation delta (positive = gain, negative = loss). 0 for show-only. */
  delta: number;
  /** True when the tag is just [FACTION:name] (show-only, no mutation). */
  showOnly: boolean;
}

interface ParsedTags {
  cleanText: string;
  mutations: InvMutation[];
  skillChanges: SkillMutation[];
  levelChanges: LevelMutation[];
  factionMutations: FactionMutation[];
}

export function parseGameTags(text: string): ParsedTags {
  const mutations: InvMutation[] = [];
  const skillChanges: SkillMutation[] = [];
  const levelChanges: LevelMutation[] = [];
  const factionMutations: FactionMutation[] = [];

  let cleanText = text;

  // Parse inventory tags: [INV:+/-item]
  cleanText = cleanText.replace(/\[INV:([+-])(\d+:)?([^\]]+)\]/gi, (_m, op: string, qtyPrefix: string | undefined, item: string) => {
    let qty = 1;
    if (qtyPrefix) {
      const n = parseInt(qtyPrefix.replace(":", ""), 10);
      if (!isNaN(n) && n > 0) qty = n;
    }
    mutations.push({ op: op === "+" ? "add" : "remove", item: item.trim(), qty });
    return "";
  });

  // Parse skill tags:
  //   [SKILL:+name] or [SKILL:+name:level]
  //   [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([+-])([^+\-\]:]+)(?::(\d+))?\]/gi, (_m, op: string, name: string, levelStr?: string) => {
    const absolute = levelStr ? parseInt(levelStr, 10) : null;
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? 1 : -1,
      absolute,
    });
    return "";
  });

  // Also handle relative: [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([^+\-\]]+)([+-])(\d+)\]/gi, (_m, name: string, op: string, nStr: string) => {
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? parseInt(nStr, 10) : -parseInt(nStr, 10),
      absolute: null,
    });
    return "";
  });

  // Parse level tags: [LEVEL:+xp]
  cleanText = cleanText.replace(/\[LEVEL:\+(\d+)\]/gi, (_m, nStr: string) => {
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > 0) {
      levelChanges.push({ xpDelta: n, levelDelta: 0 });
    }
    return "";
  });

  // Parse faction tags:
  //   [FACTION:+name:delta] or [FACTION:-name:delta] — adjust reputation
  //   [FACTION:name]                             — show-only
  cleanText = cleanText.replace(/\[FACTION:([+-]?)([^+\-\]:]+?)(?::(-?\d+))?\]/gi, (_m, op: string, name: string, deltaStr?: string) => {
    const trimmedName = name.trim();
    if (!op && !deltaStr) {
      // [FACTION:name] — show only, no mutation
      factionMutations.push({ name: trimmedName, delta: 0, showOnly: true });
    } else {
      const delta = deltaStr ? parseInt(deltaStr, 10) : 0;
      if (delta !== 0) {
        factionMutations.push({ name: trimmedName, delta, showOnly: false });
      }
    }
    return "";
  });

  return { cleanText, mutations, skillChanges, levelChanges, factionMutations };
}

import type { Persona } from "../db/repositories/personasRepo";
import { updatePersona, updatePersonaXpLevel } from "../db/repositories/personasRepo";
import { createFaction, listFactions, updateReputation } from "../db/repositories/factionsRepo";
import { parseGameTags } from "./inventoryTags";

/** Parses game tags (inventory + skill + level + faction) from the AI response,
 *  updates the persona in DB, and returns the cleaned text. */
export async function processGameResponse(
  persona: Persona | null,
  text: string,
  _chatId?: string,
): Promise<string> {
  if (!persona) return text;
  const { cleanText, mutations, skillChanges, levelChanges, factionMutations } = parseGameTags(text);
  if (mutations.length === 0 && skillChanges.length === 0 && levelChanges.length === 0 && factionMutations.length === 0) return text;

  // Apply inventory mutations
  const inv = persona.inventory ? [...persona.inventory.map((i) => ({ ...i }))] : [];
  for (const m of mutations) {
    const existing = inv.find((i) => i.item.toLowerCase() === m.item.toLowerCase());
    if (m.op === "add") {
      if (existing) {
        existing.qty += m.qty;
      } else {
        inv.push({ item: m.item, qty: m.qty });
      }
    } else {
      if (existing) {
        existing.qty -= m.qty;
        if (existing.qty <= 0) inv.splice(inv.indexOf(existing), 1);
      }
    }
  }

  // Apply skill mutations
  const skills = persona.skills ? [...persona.skills.map((s) => ({ ...s }))] : [];
  for (const s of skillChanges) {
    const existing = skills.find((sk) => sk.name.toLowerCase() === s.name.toLowerCase());
    if (s.absolute !== null) {
      // Absolute set: [SKILL:+name:3]
      if (existing) {
        existing.level = s.absolute;
      } else {
        skills.push({ name: s.name, level: s.absolute });
      }
    } else if (s.delta > 0) {
      // Relative increase: [SKILL:name+2] or [SKILL:+name]
      if (existing) {
        existing.level += s.delta;
      } else {
        skills.push({ name: s.name, level: s.delta });
      }
    } else {
      // Decrease: [SKILL:name-1] — remove if <= 0
      if (existing) {
        existing.level = Math.max(0, existing.level + s.delta);
        if (existing.level <= 0) skills.splice(skills.indexOf(existing), 1);
      }
    }
  }

  // Apply level mutations
  let xp = persona.xp ?? 0;
  let level = persona.level ?? 1;
  let hasLevelChanges = false;
  for (const lc of levelChanges) {
    if (lc.xpDelta > 0) { xp += lc.xpDelta; hasLevelChanges = true; }
    if (lc.levelDelta > 0) { level += lc.levelDelta; hasLevelChanges = true; }
  }

  // Apply faction mutations
  for (const fm of factionMutations) {
    if (fm.showOnly) continue; // show-only tags are no-ops at processing time
    try {
      const existing = await listFactions(persona.id);
      const match = existing.find(
        (f) => f.factionName.toLowerCase() === fm.name.toLowerCase(),
      );
      if (match) {
        await updateReputation(match.id, fm.delta);
      } else {
        await createFaction(persona.id, fm.name, fm.delta);
      }
    } catch {
      // Non-critical
    }
  }

  try {
    await updatePersona(persona.id, {
      name: persona.name,
      gender: persona.gender,
      age: persona.age,
      race: persona.race,
      appearance: persona.appearance,
      progression: persona.progression,
      skills,
      inventory: inv,
    });
    if (hasLevelChanges) {
      await updatePersonaXpLevel(persona.id, xp, level);
    }
  } catch {
    // Non-critical
  }

  return cleanText;
}

import { execute, newId, nowIso, query } from "../database";

export type QuestStatus = "active" | "completed" | "failed";

export interface Quest {
  id: string;
  chatId: string;
  name: string;
  description: string;
  status: QuestStatus;
  createdAt: string;
  updatedAt: string;
}

interface QuestRow {
  id: string;
  chat_id: string;
  name: string;
  description: string;
  status: string;
  created_at: string;
  updated_at: string;
}

function toQuest(row: QuestRow): Quest {
  return {
    id: row.id,
    chatId: row.chat_id,
    name: row.name,
    description: row.description,
    status: row.status as QuestStatus,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** List all quests for a chat, active first, then completed, then failed. */
export async function listQuests(chatId: string): Promise<Quest[]> {
  const rows = await query<QuestRow>(
    `SELECT * FROM quests WHERE chat_id = $1
     ORDER BY CASE status
       WHEN 'active' THEN 0
       WHEN 'completed' THEN 1
       WHEN 'failed' THEN 2
     END, created_at ASC`,
    [chatId],
  );
  return rows.map(toQuest);
}

/** Get a single quest by name within a chat (for upsert logic). */
export async function getQuestByName(
  chatId: string,
  name: string,
): Promise<Quest | null> {
  const rows = await query<QuestRow>(
    "SELECT * FROM quests WHERE chat_id = $1 AND name = $2",
    [chatId, name],
  );
  return rows[0] ? toQuest(rows[0]) : null;
}

export interface CreateQuestInput {
  chatId: string;
  name: string;
  description?: string;
}

/** Create a new quest (active by default). */
export async function createQuest(input: CreateQuestInput): Promise<Quest> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO quests (id, chat_id, name, description, status, created_at, updated_at)
     VALUES ($1, $2, $3, $4, 'active', $5, $5)`,
    [id, input.chatId, input.name, input.description ?? "", now],
  );
  return {
    id,
    chatId: input.chatId,
    name: input.name,
    description: input.description ?? "",
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
}

/** Update a quest's status (active / completed / failed). */
export async function updateQuestStatus(
  id: string,
  status: QuestStatus,
): Promise<void> {
  await execute(
    "UPDATE quests SET status = $2, updated_at = $3 WHERE id = $1",
    [id, status, nowIso()],
  );
}

/** Append a progress note to the quest description. */
export async function addQuestNote(id: string, note: string): Promise<void> {
  const now = nowIso();
  await execute(
    `UPDATE quests SET
       description = CASE
         WHEN description = '' THEN $2
         ELSE description || '\n' || $2
       END,
       updated_at = $3
     WHERE id = $1`,
    [id, note, now],
  );
}

import { execute, newId, nowIso, query } from "../database";

export interface FactionRep {
  id: string;
  personaId: string;
  factionName: string;
  reputation: number;
  createdAt: string;
  updatedAt: string;
}

interface FactionRow {
  id: string;
  persona_id: string;
  faction_name: string;
  reputation: number;
  created_at: string;
  updated_at: string;
}

function toFactionRep(row: FactionRow): FactionRep {
  return {
    id: row.id,
    personaId: row.persona_id,
    factionName: row.faction_name,
    reputation: row.reputation,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** All faction standings for a persona, ordered by name. */
export async function listFactions(personaId: string): Promise<FactionRep[]> {
  const rows = await query<FactionRow>(
    "SELECT * FROM faction_reputations WHERE persona_id = $1 ORDER BY faction_name ASC",
    [personaId],
  );
  return rows.map(toFactionRep);
}

/** Adjust reputation by `delta`, clamped to [-100, 100]. Returns the updated row. */
export async function updateReputation(
  id: string,
  delta: number,
): Promise<FactionRep | null> {
  await execute(
    `UPDATE faction_reputations
     SET reputation = MAX(-100, MIN(100, reputation + $2)),
         updated_at = $3
     WHERE id = $1`,
    [id, delta, nowIso()],
  );
  const rows = await query<FactionRow>(
    "SELECT * FROM faction_reputations WHERE id = $1",
    [id],
  );
  return rows[0] ? toFactionRep(rows[0]) : null;
}

/** Create a new faction standing for a persona, or return the existing row
 *  if this persona already has a record for that faction name. */
export async function createFaction(
  personaId: string,
  factionName: string,
  initialReputation: number = 0,
): Promise<FactionRep> {
  const existing = await query<FactionRow>(
    "SELECT * FROM faction_reputations WHERE persona_id = $1 AND faction_name = $2",
    [personaId, factionName],
  );
  if (existing[0]) return toFactionRep(existing[0]);

  const id = newId();
  const now = nowIso();
  const clamped = Math.max(-100, Math.min(100, initialReputation));
  await execute(
    `INSERT INTO faction_reputations (id, persona_id, faction_name, reputation, created_at, updated_at)
     VALUES ($1, $2, $3, $4, $5, $5)`,
    [id, personaId, factionName, clamped, now],
  );
  return {
    id,
    personaId,
    factionName,
    reputation: clamped,
    createdAt: now,
    updatedAt: now,
  };
}

import Database from "@tauri-apps/plugin-sql";

const DB_URL = "sqlite:mysillytavern.db";

let dbPromise: Promise<Database> | null = null;

/** Lazily opens (and caches) the single SQLite connection for the app. */
export function getDb(): Promise<Database> {
  if (!dbPromise) {
    dbPromise = Database.load(DB_URL);
  }
  return dbPromise;
}

export async function query<T>(sql: string, params: unknown[] = []): Promise<T[]> {
  const db = await getDb();
  return db.select<T[]>(sql, params);
}

export async function execute(sql: string, params: unknown[] = []): Promise<void> {
  const db = await getDb();
  await db.execute(sql, params);
}

export function newId(): string {
  return crypto.randomUUID();
}

export function nowIso(): string {
  return new Date().toISOString();
}

